                    {r.itemKo}
                  </span>
                ) : null}
              </th>
              <td role="cell" data-th="SPEC">
                {r.spec}
                {r.specKo ? <span lang="ko"> · {r.specKo}</span> : null}
              </td>
              <td role="cell" data-th="PRICE" className="blunt-prow__price">
