.blunt-vh {
  position: absolute !important;
  width: 1px;
  height: 1px;
  margin: -1px;
  padding: 0;
  overflow: hidden;
  clip-path: inset(50%);
  white-space: nowrap;
  border: 0;
}

/* ==========================================================================
   Press feedback — "spring-press", minus the spring.
   :active translates the element INTO its own hard shadow with a 0ms
   transition (no easing at all); release snaps back in 90ms linear.
