}

.blunt-js .blunt-sticker {
  cursor: grab;
  user-select: none;
  -webkit-user-select: none;
}

.blunt-js .blunt-sticker.is-grabbed {
  cursor: grabbing;
  filter: drop-shadow(9px 11px 0 rgba(16, 16, 16, 0.75));
}

/* Solid-ink stickers multiply — overlaps darken like stacked riso layers.
   Paper-backed decals (tag, barcode, wet-ink label) stay opaque. */
.blunt-sticker--ink {
  mix-blend-mode: multiply;
}

/* -- scatter (also the no-JS layout: same mess, just still) -------------- */
.blunt-sticker--smiley   { left: 4%;  top: 6%;  --blunt-rot: -8deg; }
.blunt-sticker--arrow    { left: 36%; top: 5%;  --blunt-rot: 3deg; }
.blunt-sticker--rush     { left: 66%; top: 8%;  --blunt-rot: -4deg; }
.blunt-sticker--barcode  { left: 8%;  top: 38%; --blunt-rot: 5deg; }
.blunt-sticker--bang     { left: 41%; top: 30%; --blunt-rot: -6deg; }
.blunt-sticker--tag      { left: 58%; top: 38%; --blunt-rot: 8deg; }
.blunt-sticker--halftone { left: 3%;  top: 66%; --blunt-rot: 0deg; }
.blunt-sticker--wet      { left: 30%; top: 66%; --blunt-rot: -5deg; }
.blunt-sticker--stamp    { left: 58%; top: 62%; --blunt-rot: 7deg; }
.blunt-sticker--over     { left: 66%; top: 68%; --blunt-rot: -2deg; }

/* -- individual decals ---------------------------------------------------- */

.blunt-rush {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 0.1em;
  padding: 0.5em 0.8em;
  background: var(--blunt-red);
  border: 3px solid var(--blunt-ink);
  color: var(--blunt-ink);
  text-align: center;
}

.blunt-rush__ko {
  font-size: 2rem;
  line-height: 1;
}

.blunt-rush__en {
  font-weight: 700;
  font-size: 0.62rem;
  letter-spacing: 0.14em;
}

.blunt-barcode__digits {
  font-family: var(--blunt-font-mono);
  font-size: 9px;
  fill: var(--blunt-ink);
}

.blunt-bang__text {
  font-family: var(--blunt-font-ko);
  font-size: 40px;
  fill: var(--blunt-paper);
  paint-order: stroke;
  stroke: var(--blunt-ink);
  stroke-width: 3px;
}

.blunt-tagart {
  display: inline-flex;
  align-items: center;
  gap: 0.55em;
  padding: 0.55em 0.85em;
  background: var(--blunt-paper);
  border: 3px solid var(--blunt-ink);
  font-weight: 700;
  font-size: 0.85rem;
  letter-spacing: 0.02em;
  clip-path: polygon(0 50%, 12px 0, 100% 0, 100% 100%, 12px 100%);
  padding-left: 1.4em;
}

.blunt-tagart__hole {
  width: 9px;
  height: 9px;
  border-radius: 50%;
  background: var(--blunt-paper);
  box-shadow: 0 0 0 3px var(--blunt-ink);
}

.blunt-halftone {
  display: block;
  width: 104px;
  height: 104px;
  border-radius: 50%;
  background-image: radial-gradient(
    var(--blunt-blue) 34%,
    transparent 36%
  );
  background-size: 9px 9px;
}

.blunt-wet {
  position: relative;
  display: flex;
  flex-direction: column;
  width: 140px;
  background: var(--blunt-paper);
  border: 3px solid var(--blunt-blue);
}

.blunt-wet__stripes {
  height: 14px;
  background: repeating-linear-gradient(
    -45deg,
    var(--blunt-blue) 0 8px,
    transparent 8px 16px
  );
  border-bottom: 3px solid var(--blunt-blue);
}

.blunt-wet__txt {
  padding: 0.45em 0.6em;
  color: var(--blunt-blue);
  font-weight: 700;
  font-size: 0.72rem;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  text-align: center;
}

.blunt-stampart {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 0.25em;
  width: 96px;
  height: 96px;
  border: 3px solid var(--blunt-red);
  border-radius: 50%;
  box-shadow: inset 0 0 0 2px var(--blunt-paper), inset 0 0 0 3px var(--blunt-red);
  color: var(--blunt-red);
  font-weight: 700;
  font-size: 1.1rem;
  letter-spacing: 0.02em;
  transform: rotate(6deg);
}

.blunt-over {
  position: relative;
  display: flex;
  flex-direction: column;
  align-items: center;
  width: 120px;
  padding-bottom: 0.2em;
}

.blunt-over__c {
  position: absolute;
  top: 0;
  width: 62px;
  height: 62px;
  border-radius: 50%;
  mix-blend-mode: multiply;
}

.blunt-over__c--blue {
  left: 8px;
  background: var(--blunt-blue);
}

.blunt-over__c--red {
  left: 46px;
  background: var(--blunt-red);
}

.blunt-over__txt {
  margin-top: 68px;
  font-weight: 700;
  font-size: 0.62rem;
  letter-spacing: 0.12em;
  text-transform: uppercase;
}

/* ==========================================================================
   04 · Price list — the brutalist ledger
   ========================================================================== */

.blunt-table {
  width: 100%;
  border: 3px solid var(--blunt-ink);
  border-collapse: collapse;
  font-size: clamp(0.82rem, 1.7vw, 1.02rem);
}

.blunt-table th,
.blunt-table td {
  padding: 0.85em 0.8em;
  border-bottom: 3px solid var(--blunt-ink);
  text-align: left;
  vertical-align: top;
}

.blunt-table thead th {
  background: var(--blunt-ink);
  color: var(--blunt-paper);
  font-weight: 700;
  letter-spacing: 0.1em;
  text-transform: uppercase;
}

.blunt-table tbody tr:nth-child(even) {
  background: var(--blunt-yellow);
}

/* rows take the press too — 3px nudge, same anti-easing */
.blunt-table tbody tr {
  transition: transform var(--blunt-press-out) linear;
}

.blunt-table tbody tr:active {
  transition-duration: var(--blunt-press-in);
  transform: translate(3px, 3px);
}

.blunt-prow__item {
  font-weight: 700;
  letter-spacing: 0.02em;
  text-transform: uppercase;
}

.blunt-prow__price {
  font-weight: 700;
  white-space: nowrap;
}

.blunt-prow--dead th,
.blunt-prow--dead td {
  text-decoration: line-through;
  text-decoration-thickness: 3px;
  text-decoration-color: var(--blunt-red);
}

.blunt-stamp {
  display: inline-block;
  padding: 0.3em 0.7em;
  border: 3px solid var(--blunt-red);
  background: rgba(255, 75, 51, 0.12);
  color: var(--blunt-ink);
  font-weight: 700;
  letter-spacing: 0.08em;
  text-decoration: none; /* inline-block stops the strike propagating */
  text-transform: uppercase;
  transform: rotate(-5deg);
}

.blunt-prices__fine {
  margin: 1em 0 0;
  font-size: clamp(0.7rem, 1.4vw, 0.85rem);
  font-weight: 700;
  letter-spacing: 0.05em;
  text-transform: uppercase;
}

/* ==========================================================================
   05 · Footer — printed in reverse
   ========================================================================== */

.blunt-footer {
  border-top: 3px solid var(--blunt-ink);
  background: var(--blunt-ink);
  color: var(--blunt-paper);
}

.blunt-footer ::selection {
  background: var(--blunt-yellow);
  color: var(--blunt-ink);
}

.blunt-footer__giant {
  max-width: 1280px;
  margin: 0 auto;
  padding: clamp(48px, 9vh, 110px) clamp(16px, 5vw, 72px) 0;
  font-family: var(--blunt-font-display);
  font-size: clamp(2.1rem, 8.4vw, 7rem);
  line-height: 0.95;
  letter-spacing: -0.015em;
  text-transform: uppercase;
}

.blunt-footer__giant :lang(ko) {
  color: var(--blunt-yellow);
}

.blunt-footer__grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(240px, 1fr));
  gap: clamp(16px, 3vw, 40px);
  max-width: 1280px;
  margin: clamp(28px, 6vh, 64px) auto 0;
  padding: 0 clamp(16px, 5vw, 72px);
}

.blunt-footer__cell {
  border-top: 3px solid var(--blunt-paper);
  padding-top: 0.8em;
}

.blunt-footer__k {
  margin: 0 0 0.4em;
  color: var(--blunt-yellow);
  font-weight: 700;
  font-size: 0.78rem;
  letter-spacing: 0.14em;
  text-transform: uppercase;
}

.blunt-footer__v {
  margin: 0;
  font-size: clamp(0.82rem, 1.7vw, 1rem);
  line-height: 1.6;
}

.blunt-footer__mail {
  text-transform: none;
  letter-spacing: 0.02em;
}

.blunt-footer__legal {
  max-width: 1280px;
  margin: 0 auto;
  padding: clamp(32px, 6vh, 72px) clamp(16px, 5vw, 72px) clamp(24px, 4vh, 48px);
  font-size: clamp(0.7rem, 1.4vw, 0.85rem);
  font-weight: 700;
  letter-spacing: 0.05em;
  text-transform: uppercase;
}

/* ==========================================================================
   Paper grain — static feTurbulence noise multiplied over the sheet
   ========================================================================== */

.blunt-grain {
  position: fixed;
  inset: 0;
  z-index: 60;
  pointer-events: none;
  mix-blend-mode: multiply;
  opacity: 0.55;
}

.blunt-grain svg {
  display: block;
  width: 100%;
  height: 100%;
}

/* ==========================================================================
   Responsive composition
   ========================================================================== */

@media (max-width: 720px) {
  /* badge joins the flow so it can't sit on the wordmark */
  .blunt-badge {
    position: static;
    align-self: flex-start;
    width: fit-content;
    margin-top: 1.2em;
    order: 5;
  }

  .blunt-hero {
    padding-top: clamp(20px, 8vh, 56px);
  }

  .blunt-sechead__note {
    margin-left: 0;
    flex-basis: 100%;
  }
}

@media (max-width: 640px) {
  /* the ledger re-grids into stacked cards; explicit ARIA roles in the
     markup keep the table semantics intact */
  .blunt-table thead {
    position: absolute;
    width: 1px;
    height: 1px;
    overflow: hidden;
    clip-path: inset(50%);
  }

  .blunt-table,
  .blunt-table tbody {
    display: block;
    border: 0;
  }

  .blunt-table tbody {
    border: 3px solid var(--blunt-ink);
  }

  .blunt-table tbody tr {
    display: block;
    padding: 0.8em 0.9em;
    border-bottom: 3px solid var(--blunt-ink);
  }

  .blunt-table tbody tr:last-child {
    border-bottom: 0;
  }

  .blunt-table tbody th,
  .blunt-table tbody td {
    display: block;
    padding: 0.15em 0;
    border-bottom: 0;
  }

  .blunt-table tbody td::before {
    content: attr(data-th) " — ";
    font-size: 0.72em;
    letter-spacing: 0.1em;
    color: rgba(16, 16, 16, 0.72);
  }
}

@media (min-width: 1440px) {
  .blunt-board {
    height: 640px;
  }
}

/* ==========================================================================
   Reduced motion — the print stands still
   (JS also gates the marquee loop and sticker inertia via
   usePrefersReducedMotion; this block covers everything CSS-driven.)
   ========================================================================== */

@media (prefers-reduced-motion: reduce) {
  .blunt-js .blunt-word::before,
  .blunt-js .blunt-word::after {
    animation: none;
  }

  .blunt-root .blunt-marquee__track {
    transform: none !important;
  }

  .blunt-root .blunt-press,
  .blunt-root .blunt-table tbody tr,
  .blunt-root .blunt-sticker {
    transition: none;
  }
}
